VALUES
  ('medical-tech-moex-02938', 'medical-tech', 'medical-tech-moex-113-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '凝血試驗APTT不是用來檢測／監控下列何者？', '["檢測intrinsic coagulation factors濃度", "檢測lupus anticoagulant", "監控heparin治療劑量", "監控coumadin治療劑量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:11+00:00", "source_pdf_sha1": "61cbbcfd788a", "answer_pdf_sha1": "41d4425a327b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 44, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02939', 'medical-tech', 'medical-tech-moex-113-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關lupus anticoagulant之檢測，下列敘述何者正確？', '["使用富含血小板血漿", "當執行1：1混合試驗時，須預先於室溫孵育混合物一小時後，再檢測凝血反應時間", "若dRVVT（dilute Russell’s viper venom time）結果正常，即可排除狼瘡抗凝血物", "確認試驗（confirmation test）需採用含較高濃度磷脂之檢驗試劑"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:11+00:00", "source_pdf_sha1": "61cbbcfd788a", "answer_pdf_sha1": "41d4425a327b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 45, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02940', 'medical-tech', 'medical-tech-moex-113-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關Factor V的敘述，下列何者最適當？', '["為一雙胜肽鏈醣蛋白（two-chain glycoprotein），胜肽鏈間以雙硫鍵（disulfide bonds）連結", "與VWF結合可以大幅穩定其結構，又稱為不穩定因子（labile factor）", "Factor V 是指其一級結構具有Arg506Gln的點突變，因此無法被activated protein C水解 Leiden", "Factor V 會導致PT與APTT明顯延長 Leiden"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:11+00:00", "source_pdf_sha1": "61cbbcfd788a", "answer_pdf_sha1": "41d4425a327b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 46, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02941', 'medical-tech', 'medical-tech-moex-113-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關INR的敘述，下列何者最適當？', '["是測試凝血內在路徑（intrinsic pathway）的活性", "是為校正在各不同實驗室之間，因使用不同thromboplastin試劑所得結果之間的差異", "以ISI（international sensitivity index）進行校正，ISI與thromboplastin 之敏感度成正比", "對於長期服用warfarin且具有較高INR基準線（baseline）的肝病患者，INR是最正確可靠的評估指標"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:11+00:00", "source_pdf_sha1": "61cbbcfd788a", "answer_pdf_sha1": "41d4425a327b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 47, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02942', 'medical-tech', 'medical-tech-moex-113-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關vitamin K對止血／凝血作用的影響，下列敘述何者最適當？', '["可以參與凝血因子活化作用的vitamin K是氧化態", "Vitamin K直接參與vitamin K-dependent凝血因子所催化的蛋白酶活性水解作用", "Vitamin K結合至vitamin K-dependent凝血因子上以增加其活性", "服用過量的warfarin時可給予適量的vitamin K，以維持正常的凝血功能"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:11+00:00", "source_pdf_sha1": "61cbbcfd788a", "answer_pdf_sha1": "41d4425a327b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 48, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02943', 'medical-tech', 'medical-tech-moex-113-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關肝素（heparin）與其相關衍生物抗凝血機制的敘述，下列何者最適當？', '["肝素可與antithrombin結合，使antithrombin構形改變而造成劑量依賴性地被抑制", "與肝素相比，low molecular weight heparin的治療效果較不適合以APTT來監控", "結合在antithrombin上的肝素，在每一次的催化過程中，會經由內質網清除而消耗", "Fondaparinux可以選擇性地抑制factor IIa而完全不影響factor Xa，故可有效預防肝素所引起的血小板低 下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:11+00:00", "source_pdf_sha1": "61cbbcfd788a", "answer_pdf_sha1": "41d4425a327b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 49, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02944', 'medical-tech', 'medical-tech-moex-113-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關血小板相關的檢測，下列敘述何者最適當？', '["血小板功能的檢測應儘量在檢體取得後8小時內進行", "進行血小板計數時，應使用肝素（heparin）為抗凝劑", "出血時間（bleeding time）延長時，可確診是血小板功能低下", "® PFA-100 可以監測血小板功能"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:11+00:00", "source_pdf_sha1": "61cbbcfd788a", "answer_pdf_sha1": "41d4425a327b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 50, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02945', 'medical-tech', 'medical-tech-moex-113-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關巨核細胞（megakaryocyte）與血小板的生合成，下列敘述何者最適當？', '["巨核細胞的分化主要在骨髓發生，然而成熟的血小板分裂釋出則在肝臟進行", "血小板的生成過程中，巨核細胞經由有絲分裂進行細胞核質分裂，同時亦增加細胞質含量，為血小板脫落 （shedding）做準備", "造血素（erythropoietin）是最主要影響巨核細胞晚期的分化及血小板成熟分裂的專一性細胞激素", "巨核細胞的分界膜系統（Demarcation system）缺陷會影響成熟血小板的分裂釋出"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:11+00:00", "source_pdf_sha1": "61cbbcfd788a", "answer_pdf_sha1": "41d4425a327b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 51, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02946', 'medical-tech', 'medical-tech-moex-113-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關Glanzmann thrombasthenia的敘述，下列何者最適當？', '["為遺傳性出血性血小板數量低下症", "主要是因為缺乏血小板表面抗原GPIb", "血小板凝集試驗（platelet aggregation test）結果多呈現異常", "血塊收縮試驗結果正常"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:11+00:00", "source_pdf_sha1": "61cbbcfd788a", "answer_pdf_sha1": "41d4425a327b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 52, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02947', 'medical-tech', 'medical-tech-moex-113-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '血小板胞器如圖所示。胞器①內含von Willebrand factor；胞器②內含serotonin；胞器③內含cathepsin 。這三種胞器分別為下列何者？', '["①α-granule；②Dense granule；③Open canalicular system", "①Dense granule；②α-granule；③Weibel-Palade body", "①α-granule；②Dense granule；③Lysosome", "①Weibel-Palade body；②Dense granule；③Open canalicular system"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:11+00:00", "source_pdf_sha1": "61cbbcfd788a", "answer_pdf_sha1": "41d4425a327b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "113", "exam_name": "113年第二次專技人員高等考試醫師中醫師考試分階段考試（第一階段考試）、牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試、1...", "original_question_number": 53, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
